// Get today and yesterday's dates
const now = new Date();
const today = now.toISOString().split('T')[0];
const yesterday = new Date(now - 86400000).toISOString().split('T')[0];

return {
  dates: [yesterday, today],
  apiBase: 'https://statsapi.mlb.com/api/v1'
};

// Combine and filter active games
const games = [
  ...($node["Get Yesterday Games"].json.dates?.[0]?.games || []),
  ...($node["Get Today Games"].json.dates?.[0]?.games || [])
];

// Calculate live window (10 min pre to 6 hours post)
const now = new Date();
const active = games.filter(g => {
  const start = new Date(g.gameDate);
  const preWindow = new Date(start - 10*60*1000);
  const postWindow = new Date(start.getTime() + 6*60*60*1000);
  return now >= preWindow && now <= postWindow;
});

return { active };

// For each active game, get live feed
const games = $input.item.json.active;
return games.map(g => ({
  json: {
    gamePk: g.gamePk,
    url: `https://statsapi.mlb.com/api/v1.1/game/${g.gamePk}/feed/live`
  }
}));

// Extract home runs from game feed
const plays = $input.item.json.liveData?.plays?.allPlays || [];
const homers = plays.filter(p => p.result?.eventType === 'home_run');

return homers.map(p => ({
  json: {
    gamePk: $input.item.json.gamePk,
    atBatIndex: p.about?.atBatIndex,
    batter: p.matchup?.batter?.fullName,
    batterId: p.matchup?.batter?.id,
    inning: `${p.about?.halfInning} ${p.about?.inning}`,
    description: p.result?.description,
    key: `${$input.item.json.gamePk}:${p.about?.atBatIndex}`
  }
}));

// Check if homer already processed
const state = JSON.parse($node["Load State"].binary.data.toString());
const seen = state.seen || {};
const videoRetries = state.video_retries || {};

const homer = $input.item.json;
if (seen[homer.key]) {
  return [];
}

const retryCount = videoRetries[homer.key] || 0;
return [{
  json: {
    ...homer,
    retryCount,
    contentUrl: `https://statsapi.mlb.com/api/v1/game/${homer.gamePk}/content`,
    mlbSearchUrl: `https://www.mlb.com/video/search?q=${encodeURIComponent(homer.batter + ' home run')}`
  }
}];

// Extract videos from content
const content = $input.item.json;
const homer = $input.item;
const items = content.highlights?.highlights?.items || [];

// Find homer videos
const hrItems = items.filter(it => {
  const title = (it.headline || it.title || '').toLowerCase();
  const isHr = title.includes('home run');
  const isBatter = homer.json.batterId ?
    it.keywordsAll?.some(k => k.type === 'player' && k.playerId === homer.json.batterId) :
    title.toLowerCase().includes(homer.json.batter.toLowerCase());
  return isHr && isBatter;
});

// Extract video URLs
let urls = [];
for (const it of hrItems) {
  for (const pb of (it.playbacks || [])) {
    if (pb.url?.endsWith('.mp4')) {
      urls.push(pb.url);
    }
  }
}

// Sort into types
const diamond = urls.filter(u => u.includes('mlb-cuts-diamond.mlb.com'));
const darkroom = urls.filter(u => u.includes('darkroom-clips.mlb.com'));
const produced = urls.filter(u => u.includes('bdata-producedclips.mlb.com'));

// Pick best URLs
let broadcast = null;
for (const u of diamond) {
  if (u.includes('4000K')) {
    broadcast = u;
    break;
  }
}
if (!broadcast && diamond.length) broadcast = diamond[0];
if (!broadcast && produced.length) broadcast = produced[0];

const animated = darkroom[0] || null;

return [{
  json: {
    ...homer.json,
    broadcast,
    animated,
    hasVideos: !!(broadcast || animated)
  }
}];

