// Create post file
const homer = items[0].json;
const date = new Date().toISOString().split('T')[0];
const ts = new Date().toISOString().replace(/[:\.-]/g, '').replace('T', '_').slice(0, 15);
const postDir = `/Users/benbirkhahn/HomerTrakker/MLB_HomeRun_Posts/${date}`;
const postPath = `${postDir}/tonights_homer_${homer.gamePk}_${ts}.txt`;

const text = `TONIGHT'S HOME RUN - READY FOR @homertrakker
=======================================================

CAPTION:
🏠⚾ HOME RUN ALERT! ⚾🏠
🔥 ${homer.batter}
📊 ${homer.inning}
${homer.description}

HASHTAGS:
#MLB #HomeRun #Baseball #MLBShorts #Statcast

VIDEOS:
1. clip
   ${homer.broadcast || ''}
${homer.animated ? `2. clip
   ${homer.animated}
` : ''}
HOME RUN DATA:
GamePk: ${homer.gamePk}
Batter: ${homer.batter}
Inning: ${homer.inning}
`;

// Ensure directory exists
if (!await $filesystem.exists(postDir)) {
  await $filesystem.mkdir(postDir, { recursive: true });
}

// Write post file
await $filesystem.writeFile(postPath, text);

// Update state
const state = JSON.parse(await $filesystem.readFile('/Users/benbirkhahn/.homer/state.json', 'utf8'));
state.seen = state.seen || {};
state.seen[homer.key] = true;
if (state.video_retries?.[homer.key]) delete state.video_retries[homer.key];
await $filesystem.writeFile('/Users/benbirkhahn/.homer/state.json', JSON.stringify(state, null, 2));

return {json: {success: true}};

// Update retry count
const homer = items[0].json;
const state = JSON.parse(await $filesystem.readFile('/Users/benbirkhahn/.homer/state.json', 'utf8'));
state.video_retries = state.video_retries || {};
state.video_retries[homer.key] = (state.video_retries[homer.key] || 0) + 1;
await $filesystem.writeFile('/Users/benbirkhahn/.homer/state.json', JSON.stringify(state, null, 2));

return {json: {retrying: true}};
